import java.io.IOException;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;

@RequestMapping(value = "/downData", method = RequestMethod.POST)
public void downData(HttpServletRequest request, HttpServletResponse response) {
    List<YdzrExcleDetail> list = new ArrayList<>();
    HSSFWorkbook book = null;
    OutputStream outputStream = null;

    String tid = request.getParameter("tid");

    try {
        // Fetch data based on the provided 'tid'
        list = cs.fnidYdzrBaseDatas(tid);

        // Set the title for the Excel sheet
        String title = "异地转入记录表";

        // Create the Excel workbook
        book = cs.createYdzrPageSheet(title, list);

        if (!CollectionUtils.isEmpty(list) && book != null) {
            // Set the download file name
            String displayName = "异地转入记录表_" + MyDateUtils.getDateVal(new Date(), "yyyyMMddHH") + ".xlsx";

            // Encode the download file name for the response header
            String downFileName = new String(java.net.URLEncoder.encode(displayName, "UTF-8").getBytes(), "ISO8859-1");

            // Set response headers
            response.setContentType("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;charset=UTF-8");
            response.setHeader("Content-disposition", "attachment;filename=" + downFileName);

            // Write the workbook to the output stream
            outputStream = response.getOutputStream();
            book.write(outputStream);
            outputStream.flush();
        } else {
            logger.info("下载异地转入列表信息为空，不能下载");
        }
    } catch (Exception e) {
        logger.error("下载异地转入列表信息表格发生异常", e);
    } finally {
        // Ensure resources are cleaned up properly
        if (book != null) {
            book = null;
        }
        if (outputStream != null) {
            try {
                outputStream.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }
}
